import React from 'react'
import ReactApexChart from 'react-apexcharts'
import './styles.css'

// Ten days of readings; each y-axis is shared by two series via a
// seriesName array (temperatures on the left, humidity on the right).
var start = new Date('01 Jun 2025 GMT').getTime()

function daily(values) {
  return values.map(function (v, i) {
    return [start + i * 86400000, v]
  })
}

var indoorTemp = daily([22, 22.5, 23, 22.8, 23.4, 23.9, 23.1, 22.6, 23.3, 23.7])
var outdoorTemp = daily([14, 16, 18.5, 17, 19.5, 22, 20, 16.5, 18, 21])
var indoorHumidity = daily([42, 44, 41, 45, 43, 40, 46, 47, 44, 42])
var outdoorHumidity = daily([58, 63, 55, 68, 60, 52, 66, 71, 62, 57])

const ApexChart = () => {
  const [state, setState] = React.useState({
    series: [
      {
        name: 'Indoor',
        data: indoorTemp,
      },
      {
        name: 'Outdoor',
        data: outdoorTemp,
      },
      {
        name: 'Indoor Humidity',
        data: indoorHumidity,
      },
      {
        name: 'Outdoor Humidity',
        data: outdoorHumidity,
      },
    ],
    options: {
      chart: {
        type: 'area',
        height: 350,
        stacked: false,
      },
      colors: ['#008FFB', '#7BC3FF', '#00E396', '#7FE7C4'],
      dataLabels: {
        enabled: false,
      },
      stroke: {
        curve: 'monotoneCubic',
        width: [4, 4, 2, 2],
        dashArray: [0, 0, 2, 2],
      },
      fill: {
        type: 'gradient',
        gradient: {
          opacityFrom: 0.35,
          opacityTo: 0.05,
        },
      },
      legend: {
        position: 'top',
        horizontalAlign: 'left',
      },
      yaxis: [
        {
          seriesName: ['Indoor', 'Outdoor'],
          axisTicks: {
            show: true,
            color: '#008FFB',
          },
          axisBorder: {
            show: true,
            color: '#008FFB',
          },
          labels: {
            style: {
              colors: '#008FFB',
            },
            formatter: (val) => {
              if (typeof val !== 'undefined') {
                return val.toFixed(0) + '°C'
              }
              return val
            },
          },
          title: {
            text: 'Temperature',
            style: {
              color: '#008FFB',
            },
          },
        },
        {
          seriesName: ['Indoor Humidity', 'Outdoor Humidity'],
          opposite: true,
          axisTicks: {
            show: true,
            color: '#00E396',
          },
          axisBorder: {
            show: true,
            color: '#00E396',
          },
          labels: {
            style: {
              colors: '#00E396',
            },
            formatter: (val) => {
              if (typeof val !== 'undefined') {
                return val.toFixed(0) + '%'
              }
              return val
            },
          },
          title: {
            text: 'Relative Humidity',
            style: {
              color: '#00E396',
            },
          },
        },
      ],
      xaxis: {
        type: 'datetime',
      },
    },
  })

  return (
    <div>
      <div id="chart">
        <ReactApexChart
          options={state.options}
          series={state.series}
          type="area"
          height={350}
        />
      </div>
    </div>
  )
}

export default ApexChart
